#include<bits/stdc++.h>
using namespace std;
int main() {
	int a[101][101] = {}, b[101][101] = {0},  c[101][101] = {0};
	char g;
	int n, m, k;

	cin >> n;
	cin >> m;
	cin >> k;
	int minn = 100000;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			cin >> g;
			a[i][j]=g-'0';
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			b[i][j] = b[i][j - 1] + a[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			c[i][j] = c[i - 1][j] + b[i][j];
		}
	}
	for (int ax = 1; ax <= n; ax++) {
		for (int ay = 1; ay <= m; ay++) {
			for (int bx = ax; bx <= n; bx++) {
				for (int by = ay; by <= m; by++) {
					if	(c[bx][by] - c[ax - 1][by] - c[bx][ay - 1] + c[ax - 1][ay - 1] >= k) {
						minn = min((bx - ax+1) * (by - ay+1), minn);
					}
				}
			}
		}

	}
	if (minn == 100000) {
		cout << 0;
		return 0;
	}
	cout << minn;
	return 0;
}
